using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        private IQueryable<int> CreateSource(int count)
        {
            return Enumerable.Range(1, count).AsQueryable();
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = CreateSource(25);

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(1, page.PageIndex);
            Assert.Equal(3, page.TotalPages);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = CreateSource(25);

            var page = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(11, page[0]);
            Assert.Equal(20, page[9]);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = CreateSource(25);

            var page = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, page.Count);
            Assert.Equal(21, page[0]);
            Assert.Equal(25, page[4]);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var source = CreateSource(25);
            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(page.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var source = CreateSource(25);
            var page = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(page.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var source = CreateSource(25);
            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.True(page.HasNextPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var source = CreateSource(25);
            var page = PaginatedList<int>.Create(source, 3, 10);

            Assert.False(page.HasNextPage);
        }

        [Fact]
        public void Create_SinglePage_NoNextNoPrevious()
        {
            var source = CreateSource(5);
            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(1, page.TotalPages);
            Assert.False(page.HasPreviousPage);
            Assert.False(page.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyPage()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(page);
            Assert.Equal(0, page.TotalPages);
            Assert.Equal(1, page.PageIndex);
        }

        [Fact]
        public void Create_ExactlyOnePageFull()
        {
            var source = CreateSource(10);
            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(1, page.TotalPages);
            Assert.False(page.HasNextPage);
            Assert.False(page.HasPreviousPage);
        }

        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };
            var page = new PaginatedList<int>(items, 30, 2, 10);

            Assert.Equal(2, page.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var page = new PaginatedList<int>(items, 25, 1, 10);

            Assert.Equal(3, page.TotalPages);
        }

        [Fact]
        public void Constructor_AddItemsToList()
        {
            var items = new List<int> { 10, 20, 30 };
            var page = new PaginatedList<int>(items, 100, 1, 10);

            Assert.Equal(3, page.Count);
            Assert.Contains(10, page);
            Assert.Contains(20, page);
            Assert.Contains(30, page);
        }

        [Fact]
        public void TotalPages_RoundsUp()
        {
            var items = new List<int>();
            var page = new PaginatedList<int>(items, 11, 1, 10);

            Assert.Equal(2, page.TotalPages);
        }

        [Fact]
        public void Create_MiddlePage_HasBothNavigation()
        {
            var source = CreateSource(30);
            var page = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(page.HasPreviousPage);
            Assert.True(page.HasNextPage);
        }
    }
}
