using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            TestHelpers.SeedStudents(_context);
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastName()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal("Anand", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Alexander", model[2].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDate()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal("Alexander", model[0].LastName); // 2020
            Assert.Equal("Alonso", model[1].LastName); // 2021
            Assert.Equal("Anand", model[2].LastName); // 2022
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal("Anand", model[0].LastName); // 2022
            Assert.Equal("Alonso", model[1].LastName); // 2021
            Assert.Equal("Alexander", model[2].LastName); // 2020
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Meredith", null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Alonso", model[0].LastName);
        }

        [Fact]
        public void Index_SearchNoMatch_ReturnsEmpty()
        {
            var result = _controller.Index(null, null, "NonExistent", null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Empty(model);
        }

        [Fact]
        public void Index_SearchString_ResetsPage()
        {
            var result = _controller.Index(null, null, "A", null) as ViewResult;

            // When searchString is non-null, page is reset to 1
            Assert.NotNull(result);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, 1) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagSortParms()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_DateSort_SetsDateSortParmToDateDesc()
        {
            _controller.Index("Date", null, null, null);

            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_Pagination_RespectsPageSize()
        {
            // Add more students to test pagination (page size is 10)
            for (int i = 4; i <= 15; i++)
            {
                _context.Students.Add(new Student
                {
                    ID = i,
                    FirstMidName = $"First{i}",
                    LastName = $"Last{i:D3}",
                    EnrollmentDate = DateTime.Parse("2020-01-01")
                });
            }
            _context.SaveChanges();

            var result = _controller.Index(null, null, null, 1) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal(10, model.Count);
            Assert.True(model.HasNextPage);
            Assert.False(model.HasPreviousPage);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Need enrollments loaded for Details
            _context.Courses.Add(new Course { CourseID = 100, Title = "Test", Credits = 3, DepartmentID = 0 });
            _context.Enrollments.Add(new Enrollment { EnrollmentID = 100, StudentID = 1, CourseID = 100 });
            _context.SaveChanges();

            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_GET_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_POST_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_POST_ValidStudent_AddsToDatabase()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.Equal(4, _context.Students.Count());
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Student>(result.Model);
        }

        [Fact]
        public void Create_POST_MinValueEnrollmentDate_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ErrorCount > 0);
        }

        [Fact]
        public void Create_POST_TooEarlyEnrollmentDate_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1752, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ErrorCount > 0);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Edit_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_POST_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Updated",
                LastName = "Alexander",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            // Detach existing tracked entity
            var tracked = _context.Students.Local.FirstOrDefault(s => s.ID == 1);
            if (tracked != null)
                _context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Updated",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_POST_MinValueEnrollmentDate_AddsModelError()
        {
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Updated",
                LastName = "Alexander",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ErrorCount > 0);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Delete_GET_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesFromDatabase()
        {
            _controller.DeleteConfirmed(1);

            Assert.Equal(2, _context.Students.Count());
            Assert.Null(_context.Students.Find(1));
        }

        #endregion
    }
}

