namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            _controller = new NotificationsController(_context);

            // Drain any leftover notifications
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain notifications after each test
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_ReturnsJson_WhenQueueEmpty()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var value = result.Value;
            Assert.NotNull(value);
        }

        [Fact]
        public void GetNotifications_ReturnsNotifications_WhenAvailable()
        {
            // Enqueue via service
            var svc = new NotificationService();
            svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
            svc.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var value = result.Value;
            Assert.NotNull(value);
            // The result should be an anonymous object with success, notifications, count
            var type = value.GetType();
            var successProp = type.GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            var svc = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();
            var value = result.Value;
            var type = value.GetType();
            var countProp = type.GetProperty("count");
            var count = (int)countProp.GetValue(value);

            Assert.True(count <= 10);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.NotNull(result);
            var value = result.Value;
            var type = value.GetType();
            var successProp = type.GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
        }
    }
}
