            Assert.Equal("Anand", model[0].LastName); // 2022
            Assert.Equal("Alonso", model[1].LastName); // 2021
            Assert.Equal("Alexander", model[2].LastName); // 2020
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
