using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsStudents()
        {
            var dbName = Guid.NewGuid().ToString();
            using var context = TestHelpers.CreateContext(dbName);

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsInstructors()
        {
            var dbName = Guid.NewGuid().ToString();
            using var context = TestHelpers.CreateContext(dbName);

            DbInitializer.Initialize(context);

            Assert.Equal(5, context.Instructors.Count());
        }

        [Fact]
        public void Initialize_SeedsDepartments()
        {
            var dbName = Guid.NewGuid().ToString();
            using var context = TestHelpers.CreateContext(dbName);

            DbInitializer.Initialize(context);

            Assert.Equal(4, context.Departments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourses()
        {
            var dbName = Guid.NewGuid().ToString();
            using var context = TestHelpers.CreateContext(dbName);

            DbInitializer.Initialize(context);

            Assert.Equal(7, context.Courses.Count());
        }

        [Fact]
        public void Initialize_SeedsEnrollments()
        {
            var dbName = Guid.NewGuid().ToString();
            using var context = TestHelpers.CreateContext(dbName);

            DbInitializer.Initialize(context);

            Assert.Equal(11, context.Enrollments.Count());
        }

        [Fact]
        public void Initialize_SeedsOfficeAssignments()
        {
            var dbName = Guid.NewGuid().ToString();
            using var context = TestHelpers.CreateContext(dbName);

            DbInitializer.Initialize(context);

            Assert.Equal(3, context.OfficeAssignments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourseAssignments()
        {
            var dbName = Guid.NewGuid().ToString();
            using var context = TestHelpers.CreateContext(dbName);

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.CourseAssignments.Count());
        }

        [Fact]
        public void Initialize_DoesNotReinsert_WhenAlreadySeeded()
        {
            var dbName = Guid.NewGuid().ToString();
            using var context = TestHelpers.CreateContext(dbName);

            DbInitializer.Initialize(context);
            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_SetsCorrectEnrollmentGrades()
        {
            var dbName = Guid.NewGuid().ToString();
            using var context = TestHelpers.CreateContext(dbName);

            DbInitializer.Initialize(context);

            var enrollmentsWithGrades = context.Enrollments.Where(e => e.Grade != null).ToList();
            var enrollmentsWithoutGrades = context.Enrollments.Where(e => e.Grade == null).ToList();

            Assert.True(enrollmentsWithGrades.Count > 0);
            Assert.True(enrollmentsWithoutGrades.Count > 0);
        }

        [Fact]
        public void Initialize_DepartmentsHaveAdministrators()
        {
            var dbName = Guid.NewGuid().ToString();
            using var context = TestHelpers.CreateContext(dbName);

            DbInitializer.Initialize(context);

            var departments = context.Departments.ToList();
            Assert.All(departments, d => Assert.NotNull(d.InstructorID));
        }
    }

    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_CanBeCreated_WithInMemoryDatabase()
        {
            using var context = TestHelpers.CreateContext();
            Assert.NotNull(context);
        }

        [Fact]
        public void SchoolContext_HasStudentsDbSet()
        {
            using var context = TestHelpers.CreateContext();
            Assert.NotNull(context.Students);
        }

        [Fact]
        public void SchoolContext_HasCoursesDbSet()
        {
            using var context = TestHelpers.CreateContext();
            Assert.NotNull(context.Courses);
        }

        [Fact]
        public void SchoolContext_HasDepartmentsDbSet()
        {
            using var context = TestHelpers.CreateContext();
            Assert.NotNull(context.Departments);
        }

        [Fact]
        public void SchoolContext_HasEnrollmentsDbSet()
        {
            using var context = TestHelpers.CreateContext();
            Assert.NotNull(context.Enrollments);
        }

        [Fact]
